// Only continue when status is QUEUED (case-insensitive)
const row = $input.first().json;
const st = String(row.status ?? '').trim().toUpperCase();
if (st !== 'QUEUED') return [];
return $input.all();

// Build OpenAI chat/completions body (json_schema). No credentials here — OpenAI is called by the HTTP Request node.
// SCHEMA injected by scripts/build_n8n_workflow.py
const SCHEMA = {"title":"DocumentaryScriptAndScenes","description":"Structured script + per-scene narration and image prompts for the AI video pipeline (OpenAI GPT-4o structured outputs).","type":"object","additionalProperties":false,"properties":{"title":{"type":"string","description":"Working title for the episode."},"full_script":{"type":"string","description":"Full narration script as continuous prose (used for TTS)."},"scenes":{"type":"array","description":"Ordered scenes: one still image + VO segment + optional motion intent later.","items":{"type":"object","additionalProperties":false,"properties":{"scene_id":{"type":"integer","description":"1-based scene index."},"narration_text":{"type":"string","description":"Spoken lines for this scene (subset of full_script)."},"visual_prompt":{"type":"string","description":"Cinematic still-image prompt for ComfyUI / SDXL."},"negative_prompt":{"type":"string","description":"Negative prompt; use empty string if none."},"approx_duration_sec":{"type":"number","description":"Target VO duration for this scene in seconds."}},"required":["scene_id","narration_text","visual_prompt","negative_prompt","approx_duration_sec"]}}},"required":["title","full_script","scenes"]};

const cfg = $input.first().json;
const topic = cfg.topic;

const openaiBody = {
  model: 'gpt-4o-mini',
  messages: [
    {
      role: 'system',
      content:
        'You are a documentary scriptwriter for a faceless YouTube channel. Output must match the JSON schema. Use cinematic, desaturated documentary tone. Keep scene count reasonable (e.g. at most 8 scenes).',
    },
    {
      role: 'user',
      content: `Topic: ${topic}\n\nProduce title, full_script, and scenes with distinct visual_prompt per scene.`,
    },
  ],
  response_format: {
    type: 'json_schema',
    json_schema: {
      name: 'script_and_scenes',
      strict: true,
      schema: SCHEMA,
    },
  },
};

return [{ json: { openaiBody } }];

// Parse OpenAI response + call mock vendors (GenAIPro, RunPod, Runway, Suno, Creatomate).
// OpenAI response is on $input; pipeline fields come from the "Pipeline config" Set node (no credentials in Code sandbox).

async function httpJson(ctx, method, url, body) {
  const opt = {
    method,
    url,
    headers: { 'Content-Type': 'application/json' },
  };
  if (body !== undefined && body !== null) {
    opt.body = JSON.stringify(body);
  }
  return await ctx.helpers.httpRequest(opt);
}

const cfg = $('Pipeline config').first().json;
const topic = cfg.topic;
// Default: Docker bridge gateway to host (n8n in Docker cannot use 127.0.0.1 for mock on host).
const base = String(cfg.vendor_base_url || 'http://172.17.0.1:8080').replace(/\/+$/, '');
const maxScenes = Number(cfg.max_scenes) || 5;

const oa = $input.first().json;
if (oa.error) {
  throw new Error(`OpenAI error: ${JSON.stringify(oa.error)}`);
}

const jsonText = oa.choices[0].message.content;
const script = JSON.parse(jsonText);

const tts = await httpJson(this, 'POST', `${base}/v1/genaipro/tts`, {
  text: script.full_script,
  voice_id: 'documentary',
  format: 'mp3',
});
const voiceUrl = tts.audio_url;

const scenes = (script.scenes || []).slice(0, maxScenes);
const sceneResults = [];

for (const scene of scenes) {
  const rp = await httpJson(this, 'POST', `${base}/v1/runpod/comfy`, {
    input: { workflow: { prompt: scene.visual_prompt } },
  });
  const rpData = await httpJson(this, 'GET', `${base}/v1/runpod/comfy/${rp.id}`);
  const imageUrl = rpData.output.images[0].url;

  const rw = await httpJson(this, 'POST', `${base}/v1/runway/video`, {
    image_url: imageUrl,
    prompt: `cinematic motion, ${scene.visual_prompt}`,
    duration_sec: Math.min(30, Math.round(Number(scene.approx_duration_sec) || 5)),
  });
  const rwDone = await httpJson(this, 'GET', `${base}/v1/runway/video/${rw.task_id}`);

  sceneResults.push({
    scene_id: scene.scene_id,
    image_url: imageUrl,
    video_url: rwDone.video_url,
  });
}

const suno = await httpJson(this, 'POST', `${base}/v1/suno/generate`, {
  prompt: `dark documentary ambient music for: ${script.title}`,
  instrumental: true,
  n_variants: 4,
});

const cm = await httpJson(this, 'POST', `${base}/v1/creatomate/renders`, {
  template_id: 'pipeline_v1',
  modifications: {
    SceneVideos: sceneResults.map((s) => s.video_url),
    VoiceUrl: voiceUrl,
    MusicUrl: suno.tracks[0].audio_url,
  },
});
const final = await httpJson(this, 'GET', `${base}/v1/creatomate/renders/${cm.render_id}`);

return [
  {
    json: {
      title: script.title,
      topic,
      vendor_base_url: base,
      voice_url: voiceUrl,
      suno_tracks: suno.tracks,
      scene_results: sceneResults,
      final_mp4_url: final.url,
      creatomate_render_id: final.render_id,
      manifest: {
        script,
        scene_results: sceneResults,
        voice_url: voiceUrl,
        music_urls: suno.tracks.map((t) => t.audio_url),
        final_video: final.url,
      },
    },
  },
];

// Build row fields for Google Sheets "Update Row" (auto-map). Match on the real column **sheet_row**
// (=ROW() value). Do not use n8n's virtual "row_number" match unless a column named row_number exists.
const pipeline = $input.first().json;
const cfg = $('Pipeline config').first().json;

const rowNum = Number(cfg.row_number ?? cfg.sheet_row);
if (!Number.isFinite(rowNum) || rowNum < 2) {
  throw new Error(
    'Add a column sheet_row with =ROW() on each data row (see templates/google_sheet_columns.csv). The rowAdded trigger does not include row numbers; =ROW() gives the row to update.',
  );
}

return [
  {
    json: {
      sheet_row: rowNum,
      status: 'COMPLETE',
      output_mp4_url: pipeline.final_mp4_url ?? '',
      voice_url: pipeline.voice_url ?? '',
      script_json_url: '',
      error_message: '',
      n8n_execution_url: '',
    },
  },
];
